// Footer.jsx — Minimal, elegant footer with social links
import { motion } from 'framer-motion';
import useScrollAnimation from '../hooks/useScrollAnimation';

const SOCIAL_LINKS = [
  {
    label: 'Instagram',
    href: '#',
    icon: (
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
        <rect x="2" y="2" width="20" height="20" rx="5" /><circle cx="12" cy="12" r="4" />
        <circle cx="17.5" cy="6.5" r="0.5" fill="currentColor" />
      </svg>
    ),
  },
  {
    label: 'Twitter',
    href: '#',
    icon: (
      <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
        <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z" />
      </svg>
    ),
  },
  {
    label: 'Pinterest',
    href: '#',
    icon: (
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
        <path d="M12 2C6.48 2 2 6.48 2 12c0 4.24 2.65 7.86 6.39 9.29-.09-.78-.17-1.98.03-2.83.19-.77 1.27-5.39 1.27-5.39s-.32-.65-.32-1.61c0-1.51.88-2.63 1.97-2.63.93 0 1.38.7 1.38 1.53 0 .93-.6 2.33-.9 3.63-.26 1.08.54 1.96 1.6 1.96 1.92 0 3.21-2.43 3.21-5.3 0-2.19-1.48-3.72-3.6-3.72-2.45 0-3.89 1.84-3.89 3.74 0 .74.28 1.53.64 1.96.07.08.08.16.06.24-.07.27-.21.86-.24.98-.04.16-.13.19-.3.12C7.4 13.5 6.8 11.76 6.8 10.5c0-2.95 2.14-5.66 6.18-5.66 3.24 0 5.76 2.31 5.76 5.39 0 3.22-2.03 5.81-4.84 5.81-.95 0-1.84-.49-2.14-1.07l-.58 2.19c-.21.8-.78 1.81-1.16 2.42.87.27 1.79.42 2.74.42 5.52 0 10-4.48 10-10S17.52 2 12 2z" />
      </svg>
    ),
  },
  {
    label: 'TikTok',
    href: '#',
    icon: (
      <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
        <path d="M19.59 6.69a4.83 4.83 0 01-3.77-4.25V2h-3.45v13.67a2.89 2.89 0 01-2.88 2.5 2.89 2.89 0 01-2.89-2.89 2.89 2.89 0 012.89-2.89c.28 0 .54.04.79.1V9.01a6.29 6.29 0 00-.79-.05 6.34 6.34 0 00-6.34 6.34 6.34 6.34 0 006.34 6.34 6.34 6.34 0 006.33-6.34V8.94a8.16 8.16 0 004.77 1.52V7.03a4.85 4.85 0 01-1-.34z" />
      </svg>
    ),
  },
];

const NAV_FOOTER = [
  { label: 'Menu', href: '#menu' },
  { label: 'Our Story', href: '#about' },
  { label: 'Voices', href: '#testimonials' },
  { label: 'Book a Table', href: '#contact' },
  { label: 'Privacy Policy', href: '#' },
];

export default function Footer() {
  const [ref, inView] = useScrollAnimation(0.1);
  const scrollTo = (href) => {
    const el = document.querySelector(href);
    if (el) el.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <footer style={{ background: '#080503', borderTop: '1px solid rgba(201,169,110,0.1)' }}>
      <div ref={ref} style={{ maxWidth: 1200, margin: '0 auto', padding: 'clamp(60px,8vw,100px) clamp(24px,6vw,80px) clamp(32px,4vw,48px)' }}>
        {/* Top row */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
          gap: 60, marginBottom: 72,
        }}>
          {/* Brand */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={inView ? { opacity: 1, y: 0 } : {}}
            transition={{ duration: 0.7 }}
          >
            <div style={{ marginBottom: 20 }}>
              <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '28px', fontWeight: 600, color: '#c9a96e', letterSpacing: '0.12em' }}>LUMIÈRE</div>
              <div style={{ fontFamily: "'Jost', sans-serif", fontSize: '9px', fontWeight: 300, color: '#a08060', letterSpacing: '0.35em', marginTop: 2 }}>COFFEE & CO.</div>
            </div>
            <p style={{ fontFamily: "'Jost', sans-serif", fontSize: '13px', fontWeight: 300, color: 'rgba(232,213,183,0.4)', lineHeight: 1.8, maxWidth: 240 }}>
              Where every cup tells a story of origin, craft, and human connection.
            </p>
          </motion.div>

          {/* Navigation */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={inView ? { opacity: 1, y: 0 } : {}}
            transition={{ duration: 0.7, delay: 0.1 }}
          >
            <div style={{ fontFamily: "'Jost', sans-serif", fontSize: '9px', letterSpacing: '0.3em', textTransform: 'uppercase', color: 'rgba(201,169,110,0.5)', marginBottom: 24 }}>
              Navigate
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
              {NAV_FOOTER.map(link => (
                <a
                  key={link.label}
                  href={link.href}
                  onClick={e => { e.preventDefault(); scrollTo(link.href); }}
                  style={{
                    fontFamily: "'Jost', sans-serif", fontSize: '13px', fontWeight: 300,
                    color: 'rgba(232,213,183,0.45)', textDecoration: 'none',
                    letterSpacing: '0.04em', transition: 'color 0.3s',
                  }}
                  onMouseEnter={e => e.target.style.color = '#c9a96e'}
                  onMouseLeave={e => e.target.style.color = 'rgba(232,213,183,0.45)'}
                >
                  {link.label}
                </a>
              ))}
            </div>
          </motion.div>

          {/* Hours */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={inView ? { opacity: 1, y: 0 } : {}}
            transition={{ duration: 0.7, delay: 0.2 }}
          >
            <div style={{ fontFamily: "'Jost', sans-serif", fontSize: '9px', letterSpacing: '0.3em', textTransform: 'uppercase', color: 'rgba(201,169,110,0.5)', marginBottom: 24 }}>
              Hours
            </div>
            {[['Monday – Friday', '7:00 AM – 8:00 PM'], ['Saturday', '8:00 AM – 9:00 PM'], ['Sunday', '9:00 AM – 7:00 PM']].map(([day, time]) => (
              <div key={day} style={{ display: 'flex', justifyContent: 'space-between', gap: 24, marginBottom: 14 }}>
                <span style={{ fontFamily: "'Jost', sans-serif", fontSize: '12px', fontWeight: 300, color: 'rgba(232,213,183,0.4)' }}>{day}</span>
                <span style={{ fontFamily: "'Jost', sans-serif", fontSize: '12px', fontWeight: 300, color: 'rgba(201,169,110,0.55)', whiteSpace: 'nowrap' }}>{time}</span>
              </div>
            ))}
          </motion.div>

          {/* Social + Newsletter */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={inView ? { opacity: 1, y: 0 } : {}}
            transition={{ duration: 0.7, delay: 0.3 }}
          >
            <div style={{ fontFamily: "'Jost', sans-serif", fontSize: '9px', letterSpacing: '0.3em', textTransform: 'uppercase', color: 'rgba(201,169,110,0.5)', marginBottom: 24 }}>
              Follow
            </div>
            <div style={{ display: 'flex', gap: 16, marginBottom: 36 }}>
              {SOCIAL_LINKS.map(s => (
                <a
                  key={s.label}
                  href={s.href}
                  aria-label={s.label}
                  style={{ color: 'rgba(201,169,110,0.4)', transition: 'color 0.3s', display: 'flex' }}
                  onMouseEnter={e => e.currentTarget.style.color = '#c9a96e'}
                  onMouseLeave={e => e.currentTarget.style.color = 'rgba(201,169,110,0.4)'}
                >
                  {s.icon}
                </a>
              ))}
            </div>
            <div style={{ fontFamily: "'Jost', sans-serif", fontSize: '9px', letterSpacing: '0.3em', textTransform: 'uppercase', color: 'rgba(201,169,110,0.5)', marginBottom: 14 }}>
              Newsletter
            </div>
            <div style={{ display: 'flex', gap: 0 }}>
              <input
                type="email"
                placeholder="your@email.com"
                style={{
                  flex: 1, background: 'transparent', border: 'none',
                  borderBottom: '1px solid rgba(201,169,110,0.2)',
                  padding: '10px 0', fontFamily: "'Jost', sans-serif",
                  fontSize: '12px', color: '#e8d5b7', outline: 'none', cursor: 'none',
                }}
              />
              <button style={{
                background: 'none', border: 'none', borderBottom: '1px solid rgba(201,169,110,0.2)',
                color: '#c9a96e', cursor: 'none', padding: '10px 8px',
                fontFamily: "'Jost', sans-serif", fontSize: '10px', letterSpacing: '0.15em',
                transition: 'color 0.3s',
              }}
              onMouseEnter={e => e.target.style.color = '#e8c988'}
              onMouseLeave={e => e.target.style.color = '#c9a96e'}
              >
                →
              </button>
            </div>
          </motion.div>
        </div>

        {/* Bottom bar */}
        <div style={{ borderTop: '1px solid rgba(201,169,110,0.08)', paddingTop: 32, display: 'flex', flexWrap: 'wrap', justifyContent: 'space-between', gap: 16, alignItems: 'center' }}>
          <span style={{ fontFamily: "'Jost', sans-serif", fontSize: '11px', fontWeight: 300, color: 'rgba(232,213,183,0.25)', letterSpacing: '0.06em' }}>
            © 2025 Lumière Coffee & Co. All rights reserved.
          </span>
          <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: '13px', fontStyle: 'italic', color: 'rgba(201,169,110,0.3)' }}>
            Crafted with care in Paris
          </span>
        </div>
      </div>
    </footer>
  );
}
